var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"DOCTOR_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"오셨습니까, 루체 조사관님.","JPN":"お帰りなさい、ルーチェ調査官。","ENG":"Hello, Investigator Luce.","TWN":"露契調查官，你來了。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성무 SI3E 도중 구조된 아이가 의식을 회복했다고 들었습니다.","JPN":"聖務SI3Eの途中に救助された子どもが意識を取り戻したと聞きました。","ENG":"I heard that the child rescued during Sacred Mission SI3IE has regained consciousness.","TWN":"我聽說在執行聖務SI3IE時救回來的人已經恢復意識，"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"저 안에 있는 아이인가요? 심문을 진행해도 되는 상태입니까?","JPN":"あの中にいる子どもですか？　審問を行っても大丈夫でしょうか。","ENG":"Is that her in there? Is she well enough to proceed with the questioning?","TWN":"她在裡面嗎？她現在的狀態適合問話嗎？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DOCTOR_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"아, 네. 구조 당시에도 특별한 외상은 없었으니까요.","JPN":"あ、はい。救助当時にも特に外傷はなかったので。","ENG":"Oh, yes. She didn't have any particular external injuries when she came here.","TWN":"是可以，我們救她的時候，她身上並無明顯外傷。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DOCTOR_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"다만……. 상당히 오랜 시간 동안 감금되어 있었던 모양입니다. 몸이 무척 쇠약했어요.","JPN":"ただ……相当長い間監禁されていたようです。とても衰弱していました。","ENG":"However... Her body is frail. It looks like she was imprisoned there for a long time.","TWN":"只是……她似乎是受到長時間的監禁，身體非常地虛弱。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그래도 다행히 지금은 많이 나아진 상태입니다.","JPN":"幸いにして、だいぶ具合は良くなってきていますが。","ENG":"Thankfully, her condition has improved.","TWN":"不過幸好她現在狀況已經好很多。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그렇군요. 그 외에 심문하면서 주의해야 할 점은 없습니까?","JPN":"そうですか。それ以外に審問中に気をつけるべき点はありませんか？","ENG":"I see. Is there anything I should keep in mind during the questioning?","TWN":"原來如此，還有什麼我在問話時需要注意的地方嗎？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOCTOR_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"정신이 불안정해서 지금처럼 격리해 둔 채로 진행하셔야겠습니다.","JPN":"精神が不安定ですので、今のように隔離した状態でおこなってもらいます。","ENG":"She's unstable, so the questioning must be done while she's quarantined.","TWN":"她現在精神狀態不太穩定，必須像現在這樣，在隔離病房裡進行問話。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOCTOR_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"무슨 일을 겪었는지 몰라도 개방된 공간에서는 무척 불안해하더군요.","JPN":"何があったのかはわかりませんが、開放された場所に置かれるととても不安そうですので。","ENG":"I'm not sure what she went through, but open spaces make her anxious.","TWN":"雖然不清楚她到底發生什麼事，但只要在開放的空間她就會變得非常不安。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"정도가 많이 심각한가요?","JPN":"深刻ですか？","ENG":"How severe is it?","TWN":"狀況很嚴重嗎？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOCTOR_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"저희들은 모종의 트라우마로 인한 유아퇴행으로 간주하고 있습니다. ","JPN":"私たちはある種のトラウマによる幼児退行と見ています。 ","ENG":"We see signs of age regression due to an unknown trauma.","TWN":"我們認為她是由於某種創傷而導致智力衰退。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"정상적인 증언 능력은 기대하기 어렵다는 말씀이로군요.","JPN":"正常な証言能力は期待できないということですね。","ENG":"So it might be difficult to expect a standard testimony from her.","TWN":"意思是以她現在的精神狀態不適合作證嗎？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"상관없습니다. 광인에게는 광인의 논리가 있기 마련이죠.","JPN":"構いません。狂人には狂人の理屈があるものです。","ENG":"No matter. Maniacs think in their own logical way.","TWN":"無所謂，我自有辦法。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"DOCTOR_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"무엇보다…… 저 아이는 1급 범죄자와 접촉했던 중요 참고인입니다.","JPN":"何より……あの子は第1級犯罪者と接触した重要参考人です。","ENG":"More importantly... She is a crucial witness who came in contact with a first-degree criminal.","TWN":"誰叫……她是和通緝重犯接觸過的重要證人。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"보고서에 베네딕트 콘스탄틴 본인이 직접 저 아이를 구출했다고 되어 있으니까요.","JPN":"報告書にはベネディクト・コンスタンティン本人が直接あの子を救出したと書いてありますから。","ENG":"The report states that she was saved by none other than Benedict Constantine himself.","TWN":"報告上說，是本尼迪克特·康斯坦丁親自將她救出來的。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"바로 심문을 시작하겠습니다. 준비해 주세요.","JPN":"すぐに審問を始めます。準備してください。","ENG":"I will start the interview right away. Please proceed with the preparations.","TWN":"我要問她話，請預備。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOCTOR_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"정말 이런 방법으로 괜찮을까요?","JPN":"本当にこんな方法で大丈夫でしょうかね。","ENG":"Are you sure about this?","TWN":"這樣真的沒問題嗎？"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"때로는 백 마디 말보다 표정과 행동이 더 많은 정보를 전달하기도 하죠.","JPN":"時には百の言葉より、表情と行動の方がより多くの情報を伝えることがあります。","ENG":"Sometimes, actions speak louder than words. Expressions as well.","TWN":"有時候說一百句話，都比不上一個表情或動作所傳達出的資訊。"},"stage":{"bg":"LAB_02","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};